-- S?lectionner toutes les colonnes
SELECT * FROM employ?s;

-- S?lectionner des colonnes sp?cifiques
SELECT id, nom, pr?nom FROM employ?s;

-- Alias de colonnes
SELECT nom AS "Nom de famille", pr?nom AS "Pr?nom" FROM employ?s;

-- Calculs dans SELECT
SELECT nom, salaire, salaire * 12 AS "Salaire Annuel" FROM employ?s;

SELECT 2 + 3 FROM DUAL;
SELECT SYSDATE FROM DUAL;
SELECT USER FROM DUAL;

-- Types num?riques
CREATE TABLE demo_num (montant NUMBER(7,2), quantite INTEGER, taux FLOAT);

-- Types caract?res
CREATE TABLE demo_txt (nom VARCHAR2(100), code CHAR(5), description CLOB);

-- Types date/heure
CREATE TABLE demo_date (date_event DATE, date_heure TIMESTAMP);

SELECT TO_CHAR(1234.56, '999,999.99') AS standard, TO_CHAR(1234.56, '000000.000') AS zeros, TO_CHAR(SYSDATE, 'DD/MM/YYYY') AS date_fr, TO_CHAR(SYSDATE, 'HH24:MI:SS') AS heure_24 FROM DUAL;
SELECT TO_NUMBER('1,234.56', '9,999.99') AS nombre FROM DUAL;
SELECT TO_DATE('25/12/2024', 'DD/MM/YYYY') AS date1, TO_DATE('2024-12-25 14:30', 'YYYY-MM-DD HH24:MI') AS date2 FROM DUAL;
SELECT NVL(commission_pct, 0) AS commission, NVL2(commission_pct, salary + (salary * commission_pct), salary) AS total, COALESCE(phone_number, email, 'No Contact') AS contact, NULLIF(10, 10) AS nullif_result FROM employees WHERE ROWNUM = 1;

SELECT * FROM employees WHERE salary > 5000 AND department_id = 50;
SELECT * FROM employees WHERE department_id = 50 OR department_id = 80;
SELECT * FROM employees WHERE NOT (department_id = 90);

SELECT * FROM employees WHERE last_name LIKE 'S%';
SELECT * FROM employees WHERE salary BETWEEN 3000 AND 8000;
SELECT * FROM employees WHERE department_id IN (50, 80, 100);

SELECT first_name, last_name, salary FROM employees ORDER BY salary DESC;
SELECT department_id, last_name, salary FROM employees ORDER BY department_id ASC, salary DESC, last_name;
SELECT first_name, last_name, salary FROM employees ORDER BY salary DESC NULLS LAST;

SELECT * FROM employees WHERE commission_pct IS NULL;
SELECT * FROM employees WHERE commission_pct IS NOT NULL;
SELECT COUNT(*) AS total, COUNT(commission_pct) AS avec_comm FROM employees;

SELECT e.last_name, d.department_name FROM employees e LEFT JOIN departments d ON e.department_id = d.department_id;
SELECT e.last_name, d.department_name FROM employees e RIGHT JOIN departments d ON e.department_id = d.department_id;
SELECT e.last_name, d.department_name FROM employees e FULL JOIN departments d ON e.department_id = d.department_id;

SELECT last_name FROM employees e WHERE EXISTS (SELECT 1 FROM employees s WHERE s.manager_id = e.employee_id);
SELECT last_name FROM employees WHERE salary > ALL (SELECT salary FROM employees WHERE department_id = 80);
SELECT last_name FROM employees WHERE salary > ANY (SELECT salary FROM employees WHERE department_id = 80);

SELECT employee_id, last_name FROM employees WHERE department_id = 50 UNION ALL SELECT employee_id, last_name FROM employees WHERE department_id = 80;
SELECT employee_id FROM employees INTERSECT SELECT employee_id FROM job_history;
SELECT employee_id FROM employees MINUS SELECT employee_id FROM job_history;

ALTER TABLE employes ADD (phone_number VARCHAR2(20));
ALTER TABLE employes MODIFY (last_name VARCHAR2(50));
ALTER TABLE employes DROP COLUMN phone_number;
ALTER TABLE employes RENAME COLUMN salary TO salaire;
ALTER TABLE employes ADD CONSTRAINT uk_email UNIQUE (email);
ALTER TABLE employes DROP CONSTRAINT uk_email;
DROP TABLE employes PURGE;

CREATE SEQUENCE seq_employes START WITH 1 INCREMENT BY 1 MINVALUE 1 MAXVALUE 999999 CACHE 20 NOCYCLE ORDER;
INSERT INTO employees (employee_id, last_name) VALUES (seq_employes.NEXTVAL, 'DUPONT');
SELECT seq_employes.CURRVAL FROM DUAL;

CREATE INDEX idx_employes_last_name ON employees(last_name);
CREATE UNIQUE INDEX idx_employes_email ON employees(email);
CREATE SYNONYM emp FOR employees;
SELECT * FROM emp;

SELECT table_name FROM user_tables;
SELECT table_name FROM all_tables WHERE owner = 'HR';
SELECT table_name FROM dba_tables WHERE owner = 'HR';

SELECT constraint_name, constraint_type, table_name FROM user_constraints WHERE table_name = 'EMPLOYEES';
SELECT column_name, data_type, nullable FROM user_tab_columns WHERE table_name = 'EMPLOYEES';
SELECT index_name, uniqueness FROM user_indexes WHERE table_name = 'EMPLOYEES';

CREATE USER alice IDENTIFIED BY "Mot2Passe123";
ALTER USER alice IDENTIFIED BY "NouveauMot2Passe";
ALTER USER alice QUOTA 100M ON users;
DROP USER alice CASCADE;

GRANT CREATE SESSION TO alice;
GRANT CREATE TABLE TO alice;
GRANT SELECT ON employees TO alice;
GRANT INSERT, UPDATE, DELETE ON employees TO alice;
REVOKE DELETE ON employees FROM alice;

CREATE ROLE lecteur;
CREATE ROLE editeur;
GRANT SELECT ANY TABLE TO lecteur;
GRANT SELECT, INSERT, UPDATE ON employees TO editeur;
GRANT lecteur TO alice;
GRANT editeur TO bob;
REVOKE editeur FROM bob;
